/* shim.c — C trampolines + importer constructor for the Go binding.
 *
 * The trampolines forward straight into the //export'ed Go functions
 * (Canonicalize / Load), whose C prototypes live in _cgo_export.h, generated by
 * cgo from main.go. We include sasso.h for the types and _cgo_export.h for the
 * Go entry points.
 */
#include <stdlib.h>
#include "sasso.h"
#include "_cgo_export.h"

int32_t go_canonicalize(void *user_data, const char *url,
                        const SassoCanonicalizeContext *ctx,
                        SassoImporterSink *sink) {
  (void)user_data;
  /* Canonicalize is the Go //export; cast away const for the cgo-generated
   * (char*) parameter types. sasso only reads these. */
  return Canonicalize((char *)url, (SassoCanonicalizeContext *)ctx, sink);
}

int32_t go_load(void *user_data, const char *canonical, SassoImporterSink *sink) {
  (void)user_data;
  return Load((char *)canonical, sink);
}

SassoImporter *make_importer(void) {
  SassoImporter *imp = (SassoImporter *)calloc(1, sizeof(SassoImporter));
  if (!imp) return NULL;
  imp->user_data = NULL;
  imp->canonicalize = go_canonicalize;
  imp->load = go_load;
  return imp;
}

void free_importer(SassoImporter *imp) { free(imp); }
